
    const money = n => new Intl.NumberFormat('en-GB',{style:'currency',currency:'GBP'}).format(n);
    const label = s => String(s).replaceAll('_',' ').replace(/\b\w/g,c=>c.toUpperCase());
    const today = new Date().toLocaleDateString('en-GB');
    const blankState = {
      user:null,
      clients:[],
      prospects:[],
      campaigns:[],
      leads:[],
      invoices:[],
      payments:[],
      messages:[],
      expenses:{adSpend:0,tools:0},
      activeClientEmail:'',
      settings:{name:'KRAVEX',vat:'',address:'',niches:['Dentists','Solicitors','Roofers','Aesthetic Clinics']}
    };
    const stored = JSON.parse(localStorage.getItem('nexgen_live_workspace') || 'null');
    const session = JSON.parse(localStorage.getItem('kravex_session') || 'null');
    const state = stored ? {...blankState, ...stored, settings:{...blankState.settings, ...(stored.settings || {}), name:'KRAVEX'}, user:session?.user || null, activeClientEmail:session?.activeClientEmail || stored.activeClientEmail || ''} : {...blankState, user:session?.user || null, activeClientEmail:session?.activeClientEmail || ''};
    if (state.storyVersion || state.clients.some(c => String(c.id || '').includes('dummy') || ['Patel Dental','Mike Roofing Manchester','Birmingham Aesthetic Clinic','Mercer & Cole Solicitors'].includes(c.business))) {
      const keepUser = session?.user || null;
      const keepClientEmail = session?.activeClientEmail || '';
      Object.assign(state, {...blankState, expenses:{adSpend:0,tools:0}, settings:{...blankState.settings, name:'KRAVEX'}, user:keepUser, activeClientEmail:keepClientEmail});
      persist();
    }
    let page=state.user === 'CLIENT' ? 'portal' : 'dashboard';
    let publicPage=state.user ? 'login' : 'home';
    const root = document.getElementById('root');
    const adminPages = ['dashboard','prospects','clients','campaigns','leads','invoices','payments','reports','settings'];
    const clientPages = ['portal','myLeads','myInvoices','myReport'];
    function currentClient(){ return state.clients.find(c => c.email === state.activeClientEmail) || state.clients[0] || null; }
    function myLeadsData(){ const client=currentClient(); return client ? state.leads.filter(l=>l.client===client.business) : []; }
    function myInvoicesData(){ const client=currentClient(); return client ? state.invoices.filter(i=>i.client===client.business) : []; }
    function persist(){ const copy = {...state, user:null}; localStorage.setItem('nexgen_live_workspace', JSON.stringify(copy)); }
    function persistSession(){ localStorage.setItem('kravex_session', JSON.stringify({user:state.user, activeClientEmail:state.activeClientEmail || ''})); }
    let authMode='signin';
    let authProvider='';
    function findClient(identity){ const value=String(identity||'').toLowerCase().trim(); return state.clients.find(c => String(c.email||'').toLowerCase()===value || String(c.phone||'').replaceAll(' ','')===value.replaceAll(' ','')); }
    function login(e){ e.preventDefault(); const f=e.target; const email=(f.email.value || '').toLowerCase(); if(email === 'admin@kravex.co.uk' && f.password.value.length > 0){ state.user = 'ADMIN'; page = 'dashboard'; persistSession(); render(); return; } const client=findClient(email); if(client && f.password.value.length > 0){ state.activeClientEmail=client.email; persist(); state.user = 'CLIENT'; page = 'portal'; persistSession(); render(); return; } document.querySelector('#login-error').hidden=false; }
    function clientLogin(provider){ authProvider=provider; authMode='provider'; render(); }
    function providerLogin(e){ e.preventDefault(); const f=e.target; const client=findClient(f.identity.value); if(client){ state.activeClientEmail=client.email; persist(); state.user='CLIENT'; page='portal'; persistSession(); render(); return; } document.querySelector('#provider-error').hidden=false; }
    function chooseProviderAccount(identity){ const client=findClient(identity); if(client){ state.activeClientEmail=client.email; persist(); state.user='CLIENT'; page='portal'; persistSession(); render(); return; } authMode='provider-other'; render(); }
    function providerCallback(e){ e.preventDefault(); const f=e.target; const client=findClient(f.identity.value); if(client){ state.activeClientEmail=client.email; persist(); state.user='CLIENT'; page='portal'; persistSession(); render(); return; } document.querySelector('#provider-error').hidden=false; }
    function signup(e){ e.preventDefault(); const f=e.target; state.clients.unshift({id:crypto.randomUUID(),business:f.business.value,contact:f.name.value,email:f.email.value,phone:f.phone.value,niche:f.niche.value,location:f.location.value,retainer:0,target:0,status:'ACTIVE',start:today}); state.activeClientEmail=f.email.value; persist(); state.user='CLIENT'; page='portal'; persistSession(); render(); }
    function setAuthMode(mode){ authMode=mode; render(); }
    function openApp(){ authMode='signin'; publicPage='login'; render(); }
    function siteNav(target){ publicPage=target; render(); }
    function providerIcon(provider){
      const icons={
        Google:'<svg width="18" height="18" viewBox="0 0 48 48" aria-hidden="true"><path fill="#FFC107" d="M43.6 20.5H42V20H24v8h11.3C33.7 32.7 29.3 36 24 36c-6.6 0-12-5.4-12-12s5.4-12 12-12c3.1 0 5.9 1.2 8 3.1l5.7-5.7C34.1 6.1 29.3 4 24 4 12.9 4 4 12.9 4 24s8.9 20 20 20 20-8.9 20-20c0-1.3-.1-2.4-.4-3.5z"/><path fill="#FF3D00" d="M6.3 14.7l6.6 4.8C14.7 15.1 19 12 24 12c3.1 0 5.9 1.2 8 3.1l5.7-5.7C34.1 6.1 29.3 4 24 4 16.3 4 9.7 8.3 6.3 14.7z"/><path fill="#4CAF50" d="M24 44c5.2 0 9.9-2 13.4-5.2l-6.2-5.2C29.2 35.1 26.7 36 24 36c-5.2 0-9.6-3.3-11.3-7.9l-6.5 5C9.5 39.6 16.2 44 24 44z"/><path fill="#1976D2" d="M43.6 20.5H42V20H24v8h11.3c-.8 2.3-2.3 4.2-4.1 5.6l6.2 5.2C36.9 39.2 44 34 44 24c0-1.3-.1-2.4-.4-3.5z"/></svg>',
        Microsoft:'<svg width="18" height="18" viewBox="0 0 23 23" aria-hidden="true"><path fill="#f25022" d="M1 1h10v10H1z"/><path fill="#7fba00" d="M12 1h10v10H12z"/><path fill="#00a4ef" d="M1 12h10v10H1z"/><path fill="#ffb900" d="M12 12h10v10H12z"/></svg>',
        Apple:'<svg width="18" height="18" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true"><path d="M16.4 1.7c0 1.2-.4 2.3-1.2 3.2-.9 1-2 1.6-3.1 1.5-.1-1.2.4-2.4 1.2-3.2.8-.9 2.1-1.6 3.1-1.5zM20.5 17.5c-.5 1.2-.8 1.8-1.5 2.9-1 1.5-2.3 3.4-4 3.4-1.5 0-1.9-1-4-1s-2.5 1-4 1c-1.7 0-3-1.7-4-3.2-2.7-4.1-3-8.8-1.3-11.3 1.2-1.8 3.1-2.8 4.9-2.8 1.8 0 2.9 1 4.4 1 1.4 0 2.3-1 4.4-1 1.6 0 3.4.9 4.5 2.4-4 2.2-3.3 7.8.6 9.6z"/></svg>',
        phone:'<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M22 16.9v3a2 2 0 0 1-2.2 2 19.8 19.8 0 0 1-8.6-3.1 19.5 19.5 0 0 1-6-6A19.8 19.8 0 0 1 2.1 4.2 2 2 0 0 1 4.1 2h3a2 2 0 0 1 2 1.7c.1 1 .4 1.9.7 2.8a2 2 0 0 1-.5 2.1L8.1 9.9a16 16 0 0 0 6 6l1.3-1.3a2 2 0 0 1 2.1-.5c.9.3 1.8.6 2.8.7a2 2 0 0 1 1.7 2.1z"/></svg>'
      };
      return icons[provider] || '';
    }
    function askLogout(){ document.body.insertAdjacentHTML('beforeend','<div class="confirm" id="logout-confirm"><div class="confirm-box"><h2>Sign out?</h2><p class="muted">Are you sure you want to sign out?</p><div class="toolbar" style="margin-top:20px"><button class="btn" onclick="confirmLogout()">Yes</button><button class="btn secondary" onclick="cancelLogout()">No</button></div></div></div>'); }
    function cancelLogout(){ document.querySelector('#logout-confirm')?.remove(); }
    function confirmLogout(){ state.user=null; state.activeClientEmail=''; localStorage.removeItem('kravex_session'); cancelLogout(); render(); }
    function nav(name){ page=name; render(); }
    function addClient(e){ e.preventDefault(); const f=e.target; state.clients.unshift({id:crypto.randomUUID(),business:f.business.value,contact:f.contact.value,email:f.email.value,phone:f.phone.value,niche:f.niche.value,location:f.location.value,retainer:Number(f.retainer.value || 0),target:Number(f.target.value || 0),status:f.status.value,start:f.start.value ? f.start.value.split('-').reverse().join('/') : today}); persist(); closeModal(); render(); }
    function addLead(e){ e.preventDefault(); const f=e.target; state.leads.unshift({id:crypto.randomUUID(),client:f.client.value,name:f.name.value,business:f.business.value,email:f.email.value,phone:f.phone.value,source:f.source.value,quality:f.quality.value,status:'NEW',date:today}); persist(); closeModal(); render(); }
    function addProspect(e){ e.preventDefault(); const f=e.target; state.prospects.unshift({id:crypto.randomUUID(),business:f.business.value,contact:f.contact.value,email:f.email.value,niche:f.niche.value,location:f.location.value,stage:'NEW_LEAD',value:Number(f.value.value),notes:f.notes.value}); persist(); closeModal(); render(); }
    function addCampaign(e){ e.preventDefault(); const f=e.target; state.campaigns.unshift({id:crypto.randomUUID(),client:f.client.value,name:f.name.value,niche:f.niche.value,method:f.method.value,target:f.target.value,budget:Number(f.budget.value || 0),prospects:Number(f.prospects.value || 0),sent:Number(f.sent.value || 0),open:Number(f.open.value || 0),reply:Number(f.reply.value || 0),positive:Number(f.positive.value || 0),calls:Number(f.calls.value || 0),status:f.status.value,notes:f.notes.value}); persist(); closeModal(); render(); }
    function addInvoice(e){ e.preventDefault(); const f=e.target; const subtotal=Number(f.amount.value), vat=f.vat.checked?subtotal*.2:0; state.invoices.unshift({id:crypto.randomUUID(),number:'KRX-2026-'+String(state.invoices.length+1).padStart(4,'0'),client:f.client.value,date:today,due:f.due.value.split('-').reverse().join('/'),subtotal,vat,total:subtotal+vat,status:'SENT'}); persist(); closeModal(); render(); }
    function addPayment(e){ e.preventDefault(); const f=e.target; const amount=Number(f.amount.value || 0); state.payments.unshift({id:crypto.randomUUID(),client:f.client.value,method:f.method.value,amount,date:today,status:'RECEIVED',reference:f.reference.value}); const invoice=state.invoices.find(i=>i.client===f.client.value && i.status!=='PAID'); if(invoice && amount>=invoice.total) invoice.status='PAID'; persist(); closeModal(); render(); }
    function openModal(type){ document.body.insertAdjacentHTML('beforeend', modals[type]()); document.querySelector('.modal').classList.add('open'); }
    function closeModal(){ document.querySelector('.modal')?.remove(); }
    function downloadCsv(){ const rows=[['Lead','Business','Email','Phone','Client','Source','Quality','Status','Date'],...state.leads.map(l=>[l.name,l.business,l.email,l.phone,l.client,l.source,l.quality,l.status,l.date])]; const csv=rows.map(r=>r.map(c=>'"'+String(c).replaceAll('"','""')+'"').join(',')).join('\\n'); const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([csv],{type:'text/csv'})); a.download='kravex-leads.csv'; a.click(); }
    function pdf(){ alert('PDF export is implemented in the full Express app with PDFKit. This no-dependency preview keeps the UI available until npm/PostgreSQL are installed.'); }
    function layout(content){ const pages=state.user==='CLIENT'?clientPages:adminPages; const names={myLeads:'My Leads',myInvoices:'My Invoices',myReport:'My Report'}; const client=currentClient(); return '<div class="app"><aside><div style="display:flex;gap:12px;align-items:center"><div class="logo">K</div><div><b>KRAVEX</b><p style="color:#cbd5e1;font-size:12px;margin-top:3px">'+(state.user==='CLIENT'?(client?client.business:'Client Portal'):'Agency Console')+'</p></div></div><nav>'+pages.map(p=>'<button class="'+(page===p?'active':'')+'" onclick="nav(\''+p+'\')">'+(names[p]||label(p))+'</button>').join('')+'</nav><button class="btn secondary" style="margin-top:22px;width:100%" onclick="askLogout()">Sign out</button></aside><main><header>Signed in as '+(state.user==='CLIENT'?(client?.contact||'Client User'):'KRAVEX Admin')+'</header><section class="page">'+content+'</section></main></div>'; }
    function table(cols,rows){ return '<div class="card" style="padding:0;overflow:auto"><table><thead><tr>'+cols.map(c=>'<th>'+c+'</th>').join('')+'</tr></thead><tbody>'+rows.map(r=>'<tr>'+r.map(c=>'<td>'+c+'</td>').join('')+'</tr>').join('')+'</tbody></table></div>'; }
    function dashboard(){ const mrr=state.clients.reduce((s,c)=>s+c.retainer,0); return '<div class="title"><div><h1>Agency Dashboard</h1><p class="muted">Track revenue, lead delivery, campaigns, and invoice risk.</p></div><div class="toolbar"><button class="btn" onclick="openModal(\'lead\')">Log Lead</button><button class="btn secondary" onclick="openModal(\'invoice\')">Create Invoice</button></div></div><div class="grid cards">'+[['Active clients',state.clients.length],['MRR',money(mrr)],['Leads this month',state.leads.length],['Prospects in pipeline',state.prospects.length]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Revenue billed</h2>'+bars([1200,1800,2100,3050,2850,3660])+'</div><div class="card"><h2>Leads delivered</h2>'+bars([9,13,18,22,25,31])+'</div></div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Campaign health</h2><p class="stat">51.4% open · 7.4% reply</p><p class="muted">2 active/paused campaigns monitored.</p></div><div class="card"><h2>Invoice alerts</h2>'+state.invoices.map(i=>'<p style="margin:8px 0">'+i.client+' · '+i.due+' · <span class="badge">'+i.status+'</span></p>').join('')+'</div></div>'; }
    function bars(vals){
      const max = Math.max(...vals, 1);
      return '<div class="bars">'+vals.map((v,i)=>'<div class="bar" style="height:'+(28 + (v / max) * 150)+'px"><span>'+['Nov','Dec','Jan','Feb','Mar','Apr'][i]+'</span></div>').join('')+'</div>';
    }
    function prospects(){ const stages=['NEW_LEAD','CONTACTED','CALL_BOOKED','PROPOSAL_SENT','NEGOTIATING','CLOSED_WON','CLOSED_LOST']; return '<div class="title"><div><h1>Prospect Pipeline</h1><p class="muted">Kanban-style CRM for businesses the agency is trying to sign.</p></div><button class="btn" onclick="openModal(\'prospect\')">Add Prospect</button></div><div class="kanban">'+stages.map(s=>'<div class="lane"><b>'+label(s)+'</b>'+state.prospects.filter(p=>p.stage===s).map(p=>'<div class="deal"><b>'+p.business+'</b><p class="muted">'+p.contact+' · '+p.location+'</p><p style="margin-top:8px">'+money(p.value)+'</p><button class="btn secondary" style="margin-top:10px" onclick="this.closest(\'.deal\').querySelector(\'.activity\').hidden=!this.closest(\'.deal\').querySelector(\'.activity\').hidden">Activity</button><p class="activity muted" hidden>'+p.notes+'</p></div>').join('')+'</div>').join('')+'</div>'; }
    function clients(){ return '<div class="title"><div><h1>Clients</h1><p class="muted">Active client management and portal credentials.</p></div><button class="btn">Add Client</button></div>'+table(['Business','Contact','Niche','Location','Retainer','Target','Status'],state.clients.map(c=>[c.business,c.contact,c.niche,c.location,money(c.retainer),c.target,'<span class="badge">'+label(c.status)+'</span>'])); }
    function campaigns(){ return '<div class="title"><div><h1>Campaign Tracker</h1><p class="muted">Cold email campaign volume and performance.</p></div><button class="btn">New Campaign</button></div>'+table(['Campaign','Niche','Prospects','Sent','Open %','Reply %','Positive','Calls','Status'],state.campaigns.map(c=>[c.name,c.niche,c.prospects,c.sent,c.open+'%',c.reply+'%',c.positive,c.calls,'<span class="badge">'+c.status+'</span>'])); }
    function leads(){ return '<div class="title"><div><h1>Lead Delivery</h1><p class="muted">Log delivered leads and export CSV per client.</p></div><div class="toolbar"><button class="btn secondary" onclick="downloadCsv()">Export CSV</button><button class="btn" onclick="openModal(\'lead\')">Log Lead</button></div></div>'+table(['Lead','Business','Email','Phone','Client','Source','Quality','Status','Delivered'],state.leads.map(l=>[l.name,l.business,l.email,l.phone,l.client,label(l.source),'<span class="badge">'+l.quality+'</span>',label(l.status),l.date])); }
    function invoices(){ return '<div class="title"><div><h1>Invoices</h1><p class="muted">UK VAT invoice tracking with PDF export in the full backend.</p></div><button class="btn" onclick="openModal(\'invoice\')">Create Invoice</button></div>'+table(['Number','Client','Due','Subtotal','VAT','Total','Status','PDF'],state.invoices.map(i=>[i.number,i.client,i.due,money(i.subtotal),money(i.vat),money(i.total),'<span class="badge">'+i.status+'</span>','<button class="btn secondary" onclick="pdf()">PDF</button>'])); }
    function portal(){ const mine=state.leads.filter(l=>l.client==='Bright Smile Dental'); return '<div class="title"><div><h1>Welcome, Bright Smile Dental</h1><p class="muted">Client-facing portal view with only this client\'s data.</p></div></div><div class="grid cards">'+[['Leads this month',mine.length+' / 30'],['Hot leads',mine.filter(l=>l.quality==='HOT').length],['Invoice status','SENT'],['Monthly retainer',money(1800)]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div>'+table(['Lead','Business','Email','Quality','Status'],mine.map(l=>[l.name,l.business,l.email,l.quality,label(l.status)]))+'</div><div class="card"><h2>Agency updates</h2>'+state.messages.map(m=>'<p style="margin:8px 0">'+m+'</p>').join('')+'</div></div>'; }
    function reports(){ return '<div class="title"><div><h1>Reporting</h1><p class="muted">Monthly agency and client performance summary.</p></div></div><div class="grid cards">'+[['Total MRR',money(3050)],['Total leads',state.leads.length],['Revenue billed',money(3660)],['Churned clients',0]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Top campaigns</h2>'+bars([12,7,4,3,2,1])+'</div><div class="card"><h2>Client status summary</h2><p class="stat">2 Active</p><p class="muted">0 paused · 0 churned</p></div></div>'; }
    function settings(){ return '<div class="title"><div><h1>Settings</h1><p class="muted">Agency profile, niches, templates, admins, and notifications.</p></div></div><div class="grid two"><div class="card"><h2>Agency profile</h2><input value="'+state.settings.name+'"><br><br><input value="'+state.settings.vat+'"><br><br><textarea>'+state.settings.address+'</textarea><br><br><label><input type="checkbox" checked> Overdue invoice alerts</label><br><label><input type="checkbox" checked> Lead target alerts</label></div><div class="card"><h2>Niches</h2>'+state.settings.niches.map(n=>'<span class="badge" style="margin:4px">'+n+'</span>').join('')+'</div><div class="card"><h2>Email template</h2><input value="Problem Aware Opener"><br><br><input value="More {niche} enquiries in {city}"><br><br><textarea>Hi {first_name}, noticed {business_name} is active in {city}...</textarea></div><div class="card"><h2>Admin users</h2><p>KRAVEX Admin · admin@kravex.co.uk</p></div></div>'; }
    function liveLastSix(values){ const padded=[0,0,0,0,0,0]; values.slice(-6).forEach((v,i)=>padded[6-Math.min(values.length,6)+i]=v); return padded; }
    function liveEmpty(text){ return '<div class="card"><p class="muted">'+text+'</p></div>'; }
    function dashboard(){ const active=state.clients.filter(c=>c.status==='ACTIVE'); const mrr=active.reduce((s,c)=>s+c.retainer,0); const avgOpen=state.campaigns.length?state.campaigns.reduce((s,c)=>s+Number(c.open||0),0)/state.campaigns.length:0; const avgReply=state.campaigns.length?state.campaigns.reduce((s,c)=>s+Number(c.reply||0),0)/state.campaigns.length:0; return '<div class="title"><div><h1>Agency Dashboard</h1><p class="muted">Live stats calculated from clients, leads, prospects, and invoices you enter.</p></div><div class="toolbar"><button class="btn" onclick="openModal(\'client\')">Add Client</button><button class="btn" onclick="openModal(\'lead\')">Log Lead</button><button class="btn secondary" onclick="openModal(\'invoice\')">Create Invoice</button></div></div><div class="grid cards">'+[['Active clients',active.length],['MRR',money(mrr)],['Leads this month',state.leads.length],['Prospects in pipeline',state.prospects.length]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Revenue billed</h2>'+bars(liveLastSix(state.invoices.map(i=>i.total)))+'</div><div class="card"><h2>Leads delivered</h2>'+bars(liveLastSix(state.leads.map((_,i)=>i+1)))+'</div></div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Campaign health</h2><p class="stat">'+avgOpen.toFixed(1)+'% open · '+avgReply.toFixed(1)+'% reply</p><p class="muted">'+state.campaigns.length+' campaigns monitored.</p></div><div class="card"><h2>Invoice alerts</h2>'+(state.invoices.length?state.invoices.map(i=>'<p style="margin:8px 0">'+i.client+' · '+i.due+' · <span class="badge">'+i.status+'</span></p>').join(''):'<p class="muted">No invoices entered yet.</p>')+'</div></div>'; }
    function clients(){ return '<div class="title"><div><h1>Clients</h1><p class="muted">Add real paying clients here. Dashboard MRR updates immediately.</p></div><button class="btn" onclick="openModal(\'client\')">Add Client</button></div>'+(state.clients.length?table(['Business','Contact','Niche','Location','Retainer','Target','Status'],state.clients.map(c=>[c.business,c.contact,c.niche,c.location,money(c.retainer),c.target,'<span class="badge">'+label(c.status)+'</span>'])):liveEmpty('No clients yet. Add your first real client to start tracking MRR.')); }
    function reports(){ const active=state.clients.filter(c=>c.status==='ACTIVE'); const churned=state.clients.filter(c=>c.status==='CHURNED').length; const billed=state.invoices.reduce((s,i)=>s+i.total,0); return '<div class="title"><div><h1>Reporting</h1><p class="muted">Live agency summary based on entered records.</p></div></div><div class="grid cards">'+[['Total MRR',money(active.reduce((s,c)=>s+c.retainer,0))],['Total leads',state.leads.length],['Revenue billed',money(billed)],['Churned clients',churned]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Top campaigns</h2>'+bars(liveLastSix(state.campaigns.map(c=>Number(c.calls||0))))+'</div><div class="card"><h2>Client status summary</h2><p class="stat">'+active.length+' Active</p><p class="muted">'+state.clients.filter(c=>c.status==='PAUSED').length+' paused · '+churned+' churned</p></div></div>'; }
    function payments(){ const received=state.payments.reduce((s,p)=>s+p.amount,0); const outstanding=state.invoices.filter(i=>i.status!=='PAID').reduce((s,i)=>s+i.total,0); return '<div class="title"><div><h1>Payments</h1><p class="muted">Track client payments and bank payout readiness. Real deposits should be handled by Stripe, GoCardless, or your bank.</p></div><button class="btn" onclick="openModal(\'payment\')">Record Payment</button></div><div class="grid cards"><div class="card"><p class="muted">Received</p><p class="stat">'+money(received)+'</p></div><div class="card"><p class="muted">Outstanding</p><p class="stat">'+money(outstanding)+'</p></div><div class="card"><p class="muted">Payout provider</p><p class="stat" style="font-size:20px">Not connected</p></div><div class="card"><p class="muted">Bank deposits</p><p class="stat" style="font-size:20px">External</p></div></div><div class="grid two" style="margin-top:18px"><div>'+(state.payments.length?table(['Client','Method','Amount','Date','Status','Reference'],state.payments.map(p=>[p.client,p.method,money(p.amount),p.date,p.status,p.reference||'-'])):liveEmpty('No payments recorded yet.'))+'</div><div class="card"><h2>Bank deposit setup</h2><p class="muted">In production, connect a payment processor, verify your KRAVEX bank account inside that provider, collect invoice payments, then reconcile payouts here. This admin page should never store bank login details or move funds directly.</p></div></div>'; }
    function portal(){ const client=state.clients[0]; if(!client) return '<div class="title"><div><h1>Client Portal</h1><p class="muted">Add a real client first, then this portal will show that client only.</p></div></div>'+liveEmpty('No client data available yet.'); const mine=state.leads.filter(l=>l.client===client.business); const invoice=state.invoices.find(i=>i.client===client.business); return '<div class="title"><div><h1>Welcome, '+client.business+'</h1><p class="muted">Client-facing portal view with only this client data.</p></div></div><div class="grid cards">'+[['Leads this month',mine.length+' / '+client.target],['Hot leads',mine.filter(l=>l.quality==='HOT').length],['Invoice status',invoice?invoice.status:'None'],['Monthly retainer',money(client.retainer)]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div>'+table(['Lead','Business','Email','Quality','Status'],mine.map(l=>[l.name,l.business,l.email,l.quality,label(l.status)]))+'</div><div class="card"><h2>Agency updates</h2>'+(state.messages.length?state.messages.map(m=>'<p style="margin:8px 0">'+m+'</p>').join(''):'<p class="muted">No updates yet.</p>')+'</div></div>'; }
    function myLeads(){ const rows=myLeadsData(); return '<div class="title"><div><h1>My Leads</h1><p class="muted">Leads delivered to your business only.</p></div></div>'+(rows.length?table(['Lead','Business','Email','Phone','Source','Quality','Status','Delivered'],rows.map(l=>[l.name,l.business,l.email,l.phone,label(l.source),l.quality,label(l.status),l.date])):liveEmpty('No leads have been delivered yet.')); }
    function myInvoices(){ const rows=myInvoicesData(); return '<div class="title"><div><h1>My Invoices</h1><p class="muted">Your invoice status and totals.</p></div></div>'+(rows.length?table(['Number','Due','Subtotal','VAT','Total','Status'],rows.map(i=>[i.number,i.due,money(i.subtotal),money(i.vat),money(i.total),i.status])):liveEmpty('No invoices available yet.')); }
    function myReport(){ const client=currentClient(); const rows=myLeadsData(); const invoices=myInvoicesData(); if(!client) return '<div class="title"><div><h1>My Report</h1><p class="muted">No client account is available yet.</p></div></div>'+liveEmpty('Ask KRAVEX to add your client account.'); return '<div class="title"><div><h1>My Report</h1><p class="muted">Monthly performance summary for '+client.business+'.</p></div></div><div class="grid cards">'+[['Leads delivered',rows.length],['Monthly target',client.target],['Hot leads',rows.filter(l=>l.quality==='HOT').length],['Invoice total',money(invoices.reduce((s,i)=>s+i.total,0))]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div>'; }
    function qualityBadge(q){ return '<span class="badge pill-'+String(q||'warm').toLowerCase()+'">'+label(q||'WARM')+'</span>'; }
    function leadCards(rows){ if(!rows.length) return liveEmpty('No leads have been delivered yet. New leads will appear here as soon as KRAVEX sends them.'); return '<div class="grid" style="gap:12px">'+rows.map(l=>'<div class="lead-card"><div class="lead-card-top"><div><b>'+l.name+'</b><p class="muted">'+l.business+'</p></div>'+qualityBadge(l.quality)+'</div><div class="grid two" style="gap:10px"><p><span class="muted">Email</span><br>'+l.email+'</p><p><span class="muted">Phone</span><br>'+(l.phone||'-')+'</p></div><div class="lead-card-top"><span class="muted">'+label(l.source)+' · '+l.date+'</span><span class="badge">'+label(l.status)+'</span></div></div>').join('')+'</div>'; }
    function invoiceCards(rows){ if(!rows.length) return liveEmpty('No invoices available yet.'); return '<div class="grid" style="gap:12px">'+rows.map(i=>'<div class="invoice-card"><div><b>'+i.number+'</b><p class="muted">Due '+i.due+' · VAT '+money(i.vat)+'</p></div><div style="text-align:right"><b>'+money(i.total)+'</b><br><span class="badge">'+i.status+'</span></div></div>').join('')+'</div>'; }
    function portal(){ const client=currentClient(); if(!client) return '<div class="title"><div><h1>Client Portal</h1><p class="muted">Your portal will appear once KRAVEX creates your client account.</p></div></div>'+liveEmpty('No client account is connected yet.'); const rows=myLeadsData(); const invoices=myInvoicesData(); const delivered=rows.length; const target=Math.max(Number(client.target||0),1); const pct=Math.min(100,Math.round((delivered/target)*100)); const hot=rows.filter(l=>l.quality==='HOT').length; const warm=rows.filter(l=>l.quality==='WARM').length; const cold=rows.filter(l=>l.quality==='COLD').length; const latest=rows.slice(0,3); return '<div class="card client-hero"><div class="title" style="margin:0"><div><h1>Welcome, '+client.business+'</h1><p class="muted">Your lead delivery dashboard for this month.</p></div><button class="btn secondary" onclick="nav(\'myLeads\')">View Leads</button></div><div style="margin-top:20px"><div class="lead-card-top"><span>'+delivered+' of '+client.target+' leads delivered</span><b>'+pct+'%</b></div><div class="progress" style="margin-top:10px"><span style="width:'+pct+'%"></span></div></div></div><div class="grid cards" style="margin-top:18px">'+[['Delivered',delivered],['Hot leads',hot],['Warm leads',warm],['Cold leads',cold]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div class="card"><div class="lead-card-top"><h2>Latest leads</h2><button class="btn secondary" onclick="nav(\'myLeads\')">Open all</button></div>'+leadCards(latest)+'</div><div class="grid" style="gap:16px"><div class="card"><div class="lead-card-top"><h2>Invoices</h2><button class="btn secondary" onclick="nav(\'myInvoices\')">View</button></div>'+invoiceCards(invoices.slice(0,2))+'</div><div class="card"><h2>Updates from KRAVEX</h2>'+(state.messages.length?state.messages.map(m=>'<p style="margin:8px 0">'+m+'</p>').join(''):'<p class="muted">No updates yet.</p>')+'</div></div></div>'; }
    function myLeads(){ const rows=myLeadsData(); return '<div class="title"><div><h1>My Leads</h1><p class="muted">Every lead KRAVEX has delivered to your business.</p></div></div>'+leadCards(rows); }
    function myInvoices(){ const rows=myInvoicesData(); return '<div class="title"><div><h1>My Invoices</h1><p class="muted">Your invoice status, due dates, VAT, and totals.</p></div></div>'+invoiceCards(rows); }
    function myReport(){ const client=currentClient(); if(!client) return '<div class="title"><div><h1>My Report</h1><p class="muted">No client account is available yet.</p></div></div>'+liveEmpty('Ask KRAVEX to add your client account.'); const rows=myLeadsData(); const invoices=myInvoicesData(); const target=Math.max(Number(client.target||0),1); const pct=Math.min(100,Math.round((rows.length/target)*100)); return '<div class="title"><div><h1>My Report</h1><p class="muted">Monthly performance summary for '+client.business+'.</p></div></div><div class="grid cards">'+[['Leads delivered',rows.length],['Monthly target',client.target],['Converted',rows.filter(l=>l.status==='CONVERTED').length],['Invoice total',money(invoices.reduce((s,i)=>s+i.total,0))]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Delivery progress</h2><div class="lead-card-top"><span>'+rows.length+' / '+client.target+' leads</span><b>'+pct+'%</b></div><div class="progress" style="margin-top:10px"><span style="width:'+pct+'%"></span></div></div><div class="card"><h2>Lead quality split</h2><p>Hot: '+rows.filter(l=>l.quality==='HOT').length+'</p><p>Warm: '+rows.filter(l=>l.quality==='WARM').length+'</p><p>Cold: '+rows.filter(l=>l.quality==='COLD').length+'</p></div></div>'; }
    function publicShell(content){ const items=['home','about','what we do','how it works','contact']; return '<div class="site"><header class="site-nav"><div class="brand"><div class="logo">K</div><span>KRAVEX</span></div><nav>'+items.map(i=>'<button class="'+(publicPage===i?'active':'')+'" onclick="siteNav(\''+i+'\')">'+label(i)+'</button>').join('')+'</nav><button class="btn" onclick="openApp()">Sign In</button></header>'+content+'</div>'; }
    function publicHome(){ return publicShell('<section class="site-section hero"><div style="position:relative;z-index:1"><div class="badge" style="background:#ffffff18;color:#dff7ff;border:1px solid #ffffff25">UK Lead Generation Agency</div><h1>Turn clicks, calls, and outreach into booked enquiries.</h1><p class="muted" style="font-size:18px;margin-top:18px;max-width:680px">KRAVEX builds lead generation systems for service businesses, then tracks every prospect, campaign, invoice, payment, and delivered lead in one clean operating system.</p><div class="toolbar" style="margin-top:28px"><button class="btn" onclick="siteNav(\'contact\')">Book a Call</button><button class="btn secondary" onclick="siteNav(\'how it works\')">How It Works</button></div></div><div class="hero-panel"><div style="display:flex;align-items:center;gap:12px;margin-bottom:18px"><div class="logo">K</div><div><h2 style="margin:0">KRAVEX OS</h2><p class="muted">Live agency control room</p></div></div><div class="grid" style="gap:12px"><div class="invoice-card" style="background:#ffffff14;border-color:#ffffff25;color:white"><div><b>Pipeline</b><p class="muted">Prospects moving to clients</p></div><span class="badge">CRM</span></div><div class="invoice-card" style="background:#ffffff14;border-color:#ffffff25;color:white"><div><b>Lead Delivery</b><p class="muted">Quality, source, status</p></div><span class="badge">Portal</span></div><div class="invoice-card" style="background:#ffffff14;border-color:#ffffff25;color:white"><div><b>Owner Amount</b><p class="muted">Paid money minus costs</p></div><span class="badge">Money</span></div></div></div></section><section class="site-section"><div class="site-grid"><div class="card"><h2>For local service businesses</h2><p class="muted">Dentists, roofers, clinics, solicitors, and SMEs that need qualified enquiries.</p></div><div class="card"><h2>Built for transparency</h2><p class="muted">Clients see leads and invoices. Admin sees operations and profitability.</p></div><div class="card"><h2>No spreadsheet chaos</h2><p class="muted">Everything from outreach to payment tracking lives inside KRAVEX.</p></div></div></section>'); }
    function publicAbout(){ return publicShell('<section class="site-section"><h1>About KRAVEX</h1><p class="muted" style="max-width:850px;margin-top:12px;font-size:17px">KRAVEX is a UK lead generation agency built for service businesses that need a predictable flow of qualified enquiries. We work with niches such as dental clinics, roofers, solicitors, aesthetic clinics, and other local SMEs.</p><div class="site-grid" style="margin-top:28px"><div class="card"><h2>Our focus</h2><p class="muted">Clear campaigns, qualified leads, and transparent reporting.</p></div><div class="card"><h2>Our promise</h2><p class="muted">You know what was delivered, where it came from, and what to do next.</p></div><div class="card"><h2>Our system</h2><p class="muted">Every client gets a portal to view leads, invoices, and updates.</p></div></div></section>'); }
    function publicWhat(){ return publicShell('<section class="site-section"><h1>What We Do</h1><p class="muted" style="max-width:850px;margin-top:12px;font-size:17px">We create and manage lead generation systems for UK businesses. The goal is simple: deliver people who are interested in your service and ready for your team to contact.</p><div class="site-grid" style="margin-top:28px"><div class="card"><h2>Cold Email Outreach</h2><p class="muted">Targeted campaigns for B2B niches and local service providers.</p></div><div class="card"><h2>Meta Ads</h2><p class="muted">Facebook and Instagram campaigns for local enquiries.</p></div><div class="card"><h2>Google Ads</h2><p class="muted">Search campaigns for people actively looking for your service.</p></div><div class="card"><h2>Lead Tracking</h2><p class="muted">Every lead is logged with quality, source, notes, and status.</p></div><div class="card"><h2>Client Portal</h2><p class="muted">Clients can see their own leads, invoices, updates, and reports.</p></div><div class="card"><h2>Reporting</h2><p class="muted">Monthly visibility into lead volume, quality, and performance.</p></div></div></section>'); }
    function publicHow(){ return publicShell('<section class="site-section"><h1>How Everything Works</h1><div class="grid" style="gap:18px;max-width:900px;margin-top:24px"><div class="card step"><b>1</b><div><h2>We understand your business</h2><p class="muted">We confirm your niche, location, offer, budget, and ideal customer.</p></div></div><div class="card step"><b>2</b><div><h2>We launch campaigns</h2><p class="muted">Depending on the niche, we use cold email, Meta Ads, Google Ads, or referrals.</p></div></div><div class="card step"><b>3</b><div><h2>We log qualified leads</h2><p class="muted">Every lead is added to KRAVEX with contact details, source, quality, and notes.</p></div></div><div class="card step"><b>4</b><div><h2>You contact the leads</h2><p class="muted">Your team calls, books, and converts enquiries into paying customers.</p></div></div><div class="card step"><b>5</b><div><h2>You see results in the portal</h2><p class="muted">Track delivered leads, invoice status, and monthly reports from one place.</p></div></div></div></section>'); }
    function publicContact(){ return publicShell('<section class="site-section"><h1>Contact KRAVEX</h1><p class="muted" style="margin-top:12px">Use this form to enquire about lead generation for your business.</p><div class="grid two" style="margin-top:24px"><form class="card" onsubmit="event.preventDefault(); alert(\'Thanks. KRAVEX will contact you.\')"><div class="grid" style="gap:12px"><input placeholder="Your name" required><input placeholder="Business name" required><input type="email" placeholder="Email" required><input placeholder="Phone"><input placeholder="Industry / niche"><textarea placeholder="What kind of leads do you need?"></textarea><button class="btn">Send Enquiry</button></div></form><div class="card"><h2>Contact details</h2><p class="muted">Email: hello@kravex.co.uk</p><p class="muted">Location: United Kingdom</p><p class="muted" style="margin-top:16px">Admin sign-in is for KRAVEX staff. Client portal access is available after account setup.</p></div></div></section>'); }
    function publicSite(){ const views={home:publicHome,about:publicAbout,'what we do':publicWhat,'how it works':publicHow,contact:publicContact}; return (views[publicPage]||publicHome)(); }
    function clientRows(){ return state.clients.map(c=>{ const delivered=state.leads.filter(l=>l.client===c.business).length; const invoice=state.invoices.find(i=>i.client===c.business); const ok=delivered>=c.target?'?':'?'; return [c.business,money(c.retainer),delivered+' / '+c.target+' '+ok,invoice?invoice.status:'None']; }); }
    function ownerAmount(){ const paid=state.invoices.filter(i=>i.status==='PAID').reduce((s,i)=>s+i.subtotal,0); const vat=state.invoices.filter(i=>i.status==='PAID').reduce((s,i)=>s+i.vat,0); const adSpend=state.expenses?.adSpend||0; const tools=state.expenses?.tools||0; const costs=adSpend+tools; return {paid,vat,adSpend,tools,costs,owner:Math.max(0,paid-costs),costsToRecover:Math.max(0,costs-paid)}; }
    function ownerBreakdown(){ const o=ownerAmount(); return '<div class="card"><h2>Owner available: '+money(o.owner)+'</h2><p class="muted">This is paid retainer money available to the owner after operating costs. VAT is shown separately so it is not mistaken for owner money.</p><div style="margin-top:12px"><div class="money-line"><span>Paid retainers ex VAT</span><b>'+money(o.paid)+'</b></div><div class="money-line"><span>VAT to set aside</span><b>'+money(o.vat)+'</b></div><div class="money-line"><span>Ad spend</span><b>'+money(o.adSpend)+'</b></div><div class="money-line"><span>Tools/software</span><b>'+money(o.tools)+'</b></div><div class="money-line"><span>Costs to recover</span><b>'+money(o.costsToRecover)+'</b></div><div class="money-line"><span>Owner available</span><b>'+money(o.owner)+'</b></div></div><p class="muted" style="margin-top:12px">Outstanding invoices are not counted until paid. Negative owner amounts are shown as costs to recover, not money you personally owe.</p></div>'; }
    function dashboard(){ const mrr=state.clients.filter(c=>c.status==='ACTIVE').reduce((s,c)=>s+c.retainer,0); const invoiced=state.invoices.reduce((s,i)=>s+i.total,0); const ownerInfo=ownerAmount(); const profit=ownerInfo.owner; const owner=ownerInfo.owner; return '<div class="title"><div><h1>KRAVEX Dashboard</h1><p class="muted">Live business information only. Numbers update from clients, invoices, payments, leads, and costs you enter.</p></div><div class="toolbar"><button class="btn" onclick="openModal(\'client\')">Add Client</button><button class="btn" onclick="openModal(\'lead\')">Log Lead</button><button class="btn secondary" onclick="openModal(\'invoice\')">Create Invoice</button></div></div><div class="grid cards">'+[['Total MRR',money(mrr)],['Total invoiced inc VAT',money(invoiced)],['Profit available',money(profit)],['Owner',money(owner)]].map(x=>'<div class="card"><p class="muted">'+x[0]+'</p><p class="stat">'+x[1]+'</p></div>').join('')+'</div><div class="grid two" style="margin-top:18px"><div><h2>Client performance</h2>'+(state.clients.length?table(['Client','Retainer','Leads Delivered','Invoice Status'],clientRows()):liveEmpty('No real clients entered yet. Add a client to start tracking real MRR.'))+'</div>'+ownerBreakdown()+'</div><div class="grid two" style="margin-top:18px"><div class="card"><h2>Operating notes</h2><p><b>Use this for:</b> real outreach, real campaigns, real lead delivery, real invoices, real payments.</p><br><p class="muted">Do not count money as yours until the invoice is paid and VAT/costs are set aside.</p></div><div class="card"><h2>Invoice alerts</h2>'+(state.invoices.length?state.invoices.map(i=>'<p style="margin:8px 0">'+i.client+' · '+i.due+' · <span class="badge">'+i.status+'</span></p>').join(''):'<p class="muted">No invoices entered yet.</p>')+'</div></div>'; }
    function campaigns(){ return '<div class="title"><div><h1>Campaign Tracker</h1><p class="muted">Track real campaigns that create leads for real clients.</p></div><button class="btn" onclick="openModal(\'campaign\')">New Campaign</button></div>'+(state.campaigns.length?table(['Campaign','Client','Niche','Method','Target','Budget','Open %','Reply %','Calls','Status'],state.campaigns.map(c=>[c.name,c.client||'-',c.niche,c.method||'Cold Email',c.target||'-',money(c.budget||0),(c.open||0)+'%',(c.reply||0)+'%',c.calls||0,'<span class="badge">'+c.status+'</span>'])):liveEmpty('No campaigns entered yet. Click New Campaign to create one.')); }
    function prospects(){ const stages=['NEW_LEAD','CONTACTED','CALL_BOOKED','PROPOSAL_SENT','NEGOTIATING','CLOSED_WON','CLOSED_LOST']; return '<div class="title"><div><h1>Prospect Pipeline</h1><p class="muted">Track real businesses you are trying to close.</p></div><button class="btn" onclick="openModal(\'prospect\')">Add Prospect</button></div><div class="kanban">'+stages.map(s=>'<div class="lane"><b>'+label(s)+'</b>'+state.prospects.filter(p=>p.stage===s).map(p=>'<div class="deal"><b>'+p.business+'</b><p class="muted">'+p.contact+' · '+p.location+'</p><p style="margin-top:8px">'+money(p.value)+'/mo</p><button class="btn secondary" style="margin-top:10px" onclick="this.closest(\'.deal\').querySelector(\'.activity\').hidden=!this.closest(\'.deal\').querySelector(\'.activity\').hidden">Activity</button><p class="activity muted" hidden>'+p.notes+'</p></div>').join('')+'</div>').join('')+'</div>'; }
    const modals = {
      lead:()=>'<div class="modal"><form onsubmit="addLead(event)"><h2>Log Lead</h2><div class="formgrid"><select name="client">'+state.clients.map(c=>'<option>'+c.business+'</option>').join('')+'</select><input name="name" placeholder="Lead name" required><input name="business" placeholder="Lead business" required><input name="email" placeholder="Lead email" required><input name="phone" placeholder="Phone"><select name="source"><option>COLD_EMAIL</option><option>META_AD</option><option>GOOGLE_AD</option><option>REFERRAL</option></select><select name="quality"><option>HOT</option><option>WARM</option><option>COLD</option></select></div><div class="toolbar" style="margin-top:16px"><button class="btn">Save</button><button type="button" class="btn secondary" onclick="closeModal()">Cancel</button></div></form></div>',
      prospect:()=>'<div class="modal"><form onsubmit="addProspect(event)"><h2>Add Prospect</h2><div class="formgrid"><input name="business" placeholder="Business name" required><input name="contact" placeholder="Contact name" required><input name="email" placeholder="Email" required><input name="niche" placeholder="Niche" required><input name="location" placeholder="UK city" required><input name="value" placeholder="Estimated value" type="number" required><textarea name="notes" placeholder="Notes"></textarea></div><div class="toolbar" style="margin-top:16px"><button class="btn">Save</button><button type="button" class="btn secondary" onclick="closeModal()">Cancel</button></div></form></div>',
      campaign:()=>'<div class="modal"><form onsubmit="addCampaign(event)"><h2>New Campaign</h2><p class="muted" style="margin-bottom:14px">Create a campaign that belongs to a real client and track the lead generation method.</p><div class="formgrid"><select name="client"><option value="">No client yet</option>'+state.clients.map(c=>'<option>'+c.business+'</option>').join('')+'</select><input name="name" placeholder="Campaign name" required><input name="niche" placeholder="Target niche" required><select name="method"><option>Cold Email</option><option>Meta Ads</option><option>Google Ads</option><option>Referral</option></select><input name="target" placeholder="Target audience / location"><input name="budget" placeholder="Monthly ad spend" type="number" value="0"><input name="prospects" placeholder="Prospects in sequence" type="number" value="0"><input name="sent" placeholder="Emails sent" type="number" value="0"><input name="open" placeholder="Open rate %" type="number" value="0"><input name="reply" placeholder="Reply rate %" type="number" value="0"><input name="positive" placeholder="Positive replies" type="number" value="0"><input name="calls" placeholder="Calls booked" type="number" value="0"><select name="status"><option>ACTIVE</option><option>PAUSED</option><option>COMPLETED</option></select><textarea name="notes" placeholder="Campaign notes"></textarea></div><div class="toolbar" style="margin-top:16px"><button class="btn">Create Campaign</button><button type="button" class="btn secondary" onclick="closeModal()">Cancel</button></div></form></div>',
      invoice:()=>'<div class="modal"><form onsubmit="addInvoice(event)"><h2>Create Invoice</h2><div class="formgrid"><select name="client">'+state.clients.map(c=>'<option>'+c.business+'</option>').join('')+'</select><input name="due" type="date" required><input name="amount" type="number" value="1500" required><label><input name="vat" type="checkbox" checked> Add UK VAT at 20%</label></div><div class="toolbar" style="margin-top:16px"><button class="btn">Save</button><button type="button" class="btn secondary" onclick="closeModal()">Cancel</button></div></form></div>',
      client:()=>'<div class="modal"><form onsubmit="addClient(event)"><h2>Add Client</h2><div class="formgrid"><input name="business" placeholder="Business name" required><input name="contact" placeholder="Contact name" required><input name="email" placeholder="Email" required><input name="phone" placeholder="Phone"><input name="niche" placeholder="Niche" required><input name="location" placeholder="UK city" required><input name="retainer" placeholder="Monthly retainer" type="number" required><input name="target" placeholder="Monthly lead target" type="number" required><input name="start" type="date"><select name="status"><option>ACTIVE</option><option>PAUSED</option><option>CHURNED</option></select></div><div class="toolbar" style="margin-top:16px"><button class="btn">Save Client</button><button type="button" class="btn secondary" onclick="closeModal()">Cancel</button></div></form></div>',
      payment:()=>'<div class="modal"><form onsubmit="addPayment(event)"><h2>Record Payment</h2><div class="formgrid"><select name="client">'+state.clients.map(c=>'<option>'+c.business+'</option>').join('')+'</select><select name="method"><option>Bank Transfer</option><option>Stripe</option><option>GoCardless</option><option>Manual Card Payment</option></select><input name="amount" placeholder="Amount received" type="number" required><input name="reference" placeholder="Reference / payout ID"></div><p class="muted" style="margin-top:12px">This records money received. Actual bank deposits are completed by your payment provider or bank.</p><div class="toolbar" style="margin-top:16px"><button class="btn">Save Payment</button><button type="button" class="btn secondary" onclick="closeModal()">Cancel</button></div></form></div>'
    };
    function render(){
      if(!state.user && publicPage!=='login'){ root.innerHTML=publicSite(); return; }
      if(!state.user){
        if(authMode==='signup'){ root.innerHTML='<div class="login"><form onsubmit="signup(event)"><div class="logo">K</div><h1 style="margin-top:18px">Create KRAVEX account</h1><p class="muted">Client portal signup</p><br><input name="business" placeholder="Business name" required><br><br><input name="name" placeholder="Your name" required><br><br><input name="email" type="email" placeholder="Email" required><br><br><input name="phone" placeholder="Phone"><br><br><input name="niche" placeholder="Industry / niche" required><br><br><input name="location" placeholder="UK city" required><br><br><button class="btn" style="width:100%">Sign Up</button><button type="button" class="btn secondary" style="width:100%;margin-top:10px" onclick="setAuthMode(\'signin\')">Back to Sign In</button></form></div>'; return; }
        if(authMode==='provider'){
          const providerName = authProvider === 'google' ? 'Google' : authProvider === 'microsoft' ? 'Microsoft' : authProvider === 'apple' ? 'Apple' : 'phone';
          const accounts = state.clients.map(c => ({name:c.contact || c.business, email:c.email || c.phone, initial:(c.contact||c.business||'C')[0]}));
          root.innerHTML='<div class="chooser"><div class="chooser-panel"><div class="chooser-top">'+providerIcon(providerName)+' Sign in with '+label(providerName)+'</div><div class="chooser-body"><div class="chooser-brand"><div class="chooser-logo">K</div><div><h1>Choose an account</h1><p class="muted" style="color:#e5e7eb;font-size:17px">to continue to <span style="color:#93c5fd">KRAVEX</span></p></div></div><div class="account-list">'+(accounts.length?accounts.map(a=>'<button class="account-row" onclick="chooseProviderAccount(&quot;'+a.email+'&quot;)"><span class="avatar">'+a.initial+'</span><span><b>'+a.name+'</b><br><small>'+a.email+'</small></span></button>').join(''):'')+'<button class="account-row" onclick="setAuthMode(&quot;provider-other&quot;)"><span class="avatar" style="background:#27272a">?</span><span><b>Use another account</b><br><small>Enter a different '+(authProvider==='phone'?'phone number':'email address')+'</small></span></button><p style="margin-top:38px;color:#d1d5db;font-size:14px;line-height:1.5">Before using this app, you can review KRAVEX privacy and terms. This preview only opens portals for matching client accounts.</p></div></div><div class="chooser-footer"><span>English (United Kingdom)</span><div class="chooser-links"><span>Help</span><span>Privacy</span><span>Terms</span></div></div></div></div>';
          return;
        }
        if(authMode==='provider-other'){
          const providerLabel = authProvider === 'phone' ? 'phone number' : authProvider + ' email';
          const type = authProvider === 'phone' ? 'tel' : 'email';
          root.innerHTML='<div class="login"><form onsubmit="providerLogin(event)"><div class="logo">K</div><h1 style="margin-top:18px">Use another account</h1><p class="muted">Enter the '+providerLabel+' connected to your KRAVEX client account.</p><br><input name="identity" type="'+type+'" placeholder="Enter your '+providerLabel+'" required><p id="provider-error" class="muted" style="color:#dc2626;margin-top:10px" hidden>No client account found for this login. Ask KRAVEX to create your portal account, or sign up below.</p><div style="height:18px"></div><button class="btn" style="width:100%">Continue</button><button type="button" class="btn secondary" style="width:100%;margin-top:10px" onclick="setAuthMode(\'signup\')">Sign Up</button><button type="button" class="btn secondary" style="width:100%;margin-top:10px" onclick="setAuthMode(\'provider\')">Back</button></form></div>';
          return;
        }
        const providerButtons =
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'google\')">'+providerIcon('Google')+' Continue with Google</button>'+
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'microsoft\')">'+providerIcon('Microsoft')+' Continue with Microsoft</button>'+
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'apple\')">'+providerIcon('Apple')+' Continue with Apple</button>'+
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'phone\')">'+providerIcon('phone')+' Continue with phone</button>';
        root.innerHTML='<div class="login"><form onsubmit="login(event)"><div class="logo">K</div><h1 style="margin-top:18px">KRAVEX</h1><br><input name="email" type="email" placeholder="Email address" autocomplete="username"><br><br><input name="password" type="password" placeholder="Password" autocomplete="current-password"><p id="login-error" class="muted" style="color:#dc2626;margin-top:10px" hidden>Enter your email and password.</p><div style="height:22px"></div><button class="btn" style="width:100%">Sign In</button><div style="display:flex;align-items:center;gap:12px;margin:24px 0 16px"><span style="height:1px;background:#e2e8f0;flex:1"></span><span class="muted">Client portal</span><span style="height:1px;background:#e2e8f0;flex:1"></span></div><div class="grid" style="gap:10px">'+providerButtons+'</div><p class="muted" style="text-align:center;margin-top:18px">No account? <button type="button" style="border:0;background:transparent;color:#3b82f6;font-weight:800" onclick="setAuthMode(\'signup\')">Sign Up</button></p></form></div>'; return; }
      const views={dashboard,prospects,clients,campaigns,leads,invoices,payments,portal,reports,settings,myLeads,myInvoices,myReport};
      root.innerHTML=layout(views[page]());
    }
    render = function(){
      if(!state.user && publicPage!=='login'){ root.innerHTML=publicSite(); return; }
      if(!state.user){
        if(authMode==='signup'){ root.innerHTML='<div class="login"><form onsubmit="signup(event)"><div class="logo">K</div><h1 style="margin-top:18px">Create KRAVEX account</h1><p class="muted">Client portal signup</p><br><input name="business" placeholder="Business name" required><br><br><input name="name" placeholder="Your name" required><br><br><input name="email" type="email" placeholder="Email" required><br><br><input name="phone" placeholder="Phone"><br><br><input name="niche" placeholder="Industry / niche" required><br><br><input name="location" placeholder="UK city" required><br><br><button class="btn" style="width:100%">Sign Up</button><button type="button" class="btn secondary" style="width:100%;margin-top:10px" onclick="setAuthMode(\'signin\')">Back to Sign In</button></form></div>'; return; }
        if(authMode==='provider'){
          const providerName = authProvider === 'google' ? 'Google' : authProvider === 'microsoft' ? 'Microsoft' : authProvider === 'apple' ? 'Apple' : 'phone';
          const identityType = authProvider === 'phone' ? 'phone number' : 'verified email';
          const type = authProvider === 'phone' ? 'tel' : 'email';
          root.innerHTML='<div class="oauth"><form class="oauth-card" onsubmit="providerCallback(event)"><div class="logo">K</div><h1 style="margin-top:18px">Redirect to '+label(providerName)+'</h1><p class="muted" style="font-size:15px;line-height:1.5">In production, this sends the client to the real '+label(providerName)+' sign-in page. KRAVEX never asks for or stores their '+label(providerName)+' password. After '+label(providerName)+' verifies them, it redirects back to KRAVEX with their '+identityType+'.</p><div class="oauth-provider" style="margin:20px 0">'+providerIcon(providerName)+' Continue with '+label(providerName)+'</div><p class="muted">Preview callback</p><input name="identity" type="'+type+'" placeholder="Enter the client '+identityType+' returned by '+label(providerName)+'" required><p id="provider-error" class="muted" style="color:#dc2626;margin-top:10px" hidden>No KRAVEX client account matches this identity.</p><div style="height:18px"></div><button class="btn" style="width:100%">Simulate Verified Sign In</button><button type="button" class="btn secondary" style="width:100%;margin-top:10px" onclick="setAuthMode(\'signin\')">Back</button></form></div>'; return;
        }
        const providerButtons =
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'google\')">'+providerIcon('Google')+' Continue with Google</button>'+
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'microsoft\')">'+providerIcon('Microsoft')+' Continue with Microsoft</button>'+
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'apple\')">'+providerIcon('Apple')+' Continue with Apple</button>'+
          '<button type="button" class="btn secondary" style="display:flex;align-items:center;gap:10px;justify-content:center" onclick="clientLogin(\'phone\')">'+providerIcon('phone')+' Continue with phone</button>';
        root.innerHTML='<div class="login"><form onsubmit="login(event)"><div class="logo">K</div><h1 style="margin-top:18px">KRAVEX</h1><br><input name="email" type="email" placeholder="Email address" autocomplete="username"><br><br><input name="password" type="password" placeholder="Password" autocomplete="current-password"><p id="login-error" class="muted" style="color:#dc2626;margin-top:10px" hidden>Enter your email and password.</p><div style="height:22px"></div><button class="btn" style="width:100%">Sign In</button><div style="display:flex;align-items:center;gap:12px;margin:24px 0 16px"><span style="height:1px;background:#e2e8f0;flex:1"></span><span class="muted">Client portal</span><span style="height:1px;background:#e2e8f0;flex:1"></span></div><div class="grid" style="gap:10px">'+providerButtons+'</div><p class="muted" style="text-align:center;margin-top:18px">No account? <button type="button" style="border:0;background:transparent;color:#3b82f6;font-weight:800" onclick="setAuthMode(\'signup\')">Sign Up</button></p></form></div>'; return;
      }
      const views={dashboard,prospects,clients,campaigns,leads,invoices,payments,portal,reports,settings,myLeads,myInvoices,myReport};
      root.innerHTML=layout(views[page]());
    };
    render();
  
